blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>trzy artykuły</strong> języka angielskiego: <strong>a</strong>, <strong>an</strong> i <strong>the</strong> – kiedy ich używać, a kiedy się bez nich obejść.",
    "rules": [
        {
            "label": "A / ",
            "color": "emerald",
            "text": "<strong>Przedmiot nieokreślony</strong> - coś ogólnego lub nowego:",
            "example": "Widziałem psa. / Ona jest inżynierem."
        },
        {
            "label": "[[CODX_SEG_6]]]<strong>Określony artykuł</strong> to coś konkretnego lub znanego:",
            "color": "blue",
            "text": "<strong>Означений артикль</strong> — щось конкретне або відоме:",
            "example": "Pies był duży. / Słońce jasno świeci."
        },
        {
            "label": "Zero (Ř)",
            "color": "amber",
            "text": "<strong>Brak artykułu</strong> - pojęcia ogólne, liczba mnoga:",
            "example": "Kocham muzykę. / Psy są lojalne."
        }
    ]
}

{
    "title": "1. Trzy rodzaje przedimków",
    "intro": "W języku angielskim istnieją trzy sposoby wykorzystania przedimków:",
    "items": [
        {
            "label": "A/An",
            "title": "Nieokreślony",
            "subtitle": "Przedmiot nieokreślony — coś nowego lub ogólnego (książka, artykuł jabłko)"
        },
        {
            "label": "",
            "title": "Określony",
            "subtitle": "Określony artykuł — coś konkretnego lub znanego (książka, którą kupiłem)"
        },
        {
            "label": "Zero Ø",
            "title": "Brak artykułu",
            "subtitle": "Zero artykuł — pojęcia abstrakcyjne, ogólna liczba mnoga (kocham muzykę)"
        }
    ]
}

{
    "title": "2. A vs An - kiedy który?",
    "sections": [
        {
            "label": "A - przed spółgłoską SOUND",
            "color": "emerald",
            "description": "Przedmiotek <strong>a</strong> jest używany przed słowami <strong>zaczynającymi się od spółgłoski</strong>.",
            "examples": [
                {
                    "en": "książka, samochód, pies",
                    "ua": "książka, samochód, pies"
                },
                {
                    "en": "uniwersytet [juːnɪˈvɜːsɪti]",
                    "ua": "uniwersytet (dźwięk [j] to spółgłoska!)"
                },
                {
                    "en": "kraj europejski",
                    "ua": "kraj europejski (dźwięk [j])"
                },
                {
                    "en": "jednokierunkowy ulica",
                    "ua": "ulica jednokierunkowa (dźwięk (w)) pomysł"
                }
            ]
        },
        {
            "label": "An — перед голосним ЗВУКОМ",
            "color": "sky",
            "description": "Артикль <strong>an</strong> вживається перед словами, що <strong>починаються з голосного звуку</strong>.",
            "examples": [
                {
                    "en": "an apple, an egg, an idea",
                    "ua": "яблуко, яйце, ідея"
                },
                {
                    "en": "godzina [aʊə]",
                    "ua": "godzina (h jest cicho, dźwięk [aʊ] jest głośny!)"
                },
                {
                    "en": "uczciwa osoba",
                    "ua": "uczciwa osoba (h milczy)"
                },
                {
                    "en": "stopień MBA",
                    "ua": "stopień MBA (dźwięk [e] - samogłoska)"
                }
            ]
        },
        {
            "label": "Ważne!",
            "color": "amber",
            "description": "Wybór a/an zależy od <strong>DŹWIĘKU</strong>, a nie od litera!",
            "examples": [
                {
                    "en": "mundur (dźwięk [j])",
                    "ua": "mundur"
                },
                {
                    "en": "parasol (dźwięk [ʌ])",
                    "ua": "parasol"
                }
            ],
            "note": "📌 Spójrz na wymowę, a nie ortografia!"
        }
    ]
}

{
    "title": "3. Kiedy używać A / An (nieokreślone)",
    "sections": [
        {
            "label": "Coś nowego/po raz pierwszy",
            "color": "emerald",
            "description": "Kiedy <strong>pierwszy raz wspominamy</strong> o czymś lub <strong>nie określamy</strong> co dokładnie.",
            "examples": [
                {
                    "en": "Widziałem kota w ogrodzie.",
                    "ua": "Widziałem kota w ogrodzie. (niektóre nieznane)"
                },
                {
                    "en": "Kupiła nową sukienkę.",
                    "ua": "Kupiła nową sukienkę."
                },
                {
                    "en": "Wystąpił problem.",
                    "ua": "Wystąpił problem. (niektóre)"
                }
            ]
        },
        {
            "label": "Zawody i role",
            "color": "sky",
            "description": "Kiedy mówimy o <strong>zawodzie, narodowości, religii</strong>.",
            "examples": [
                {
                    "en": "Ona jest lekarzem.",
                    "ua": "Ona jest lekarzem."
                },
                {
                    "en": "On jest lekarzem inżynier.",
                    "ua": "Inżynier."
                },
                {
                    "en": "Jestem studentem.",
                    "ua": "Jestem studentem."
                }
            ]
        },
        {
            "label": "Jeden z wielu",
            "color": "amber",
            "description": "Kiedy mamy na myśli <strong>jednego przedstawiciela firmy grupa</strong>.",
            "examples": [
                {
                    "en": "Pies to lojalne zwierzę.",
                    "ua": "Pies to lojalne zwierzę. (dowolny pies)"
                },
                {
                    "en": "Potrzebuję długopisu.",
                    "ua": "Potrzebuję długopisu. (dowolny)"
                }
            ],
            "note": "A/An = „jeden”, „jakiś”, „dowolny”."
        }
    ]
}

{
    "title": "4. Kiedy używać THE (wyznaczone)",
    "sections": [
        {
            "label": "Już znane/wspomniane",
            "color": "blue",
            "description": "Kiedy rozmówca <strong>wie</strong>, co się mówi, lub zostało to już <strong>wspomniane</strong>.",
            "examples": [
                {
                    "en": "Widziałem kota. Kot był czarny.",
                    "ua": "Widziałem kota. Kot był czarny."
                },
                {
                    "en": "Gdzie jest łazienka?",
                    "ua": "Gdzie jest łazienka? (w tym domu)"
                },
                {
                    "en": "Czy czytałeś książkę, którą ci dałem?",
                    "ua": "Czy czytałeś książkę, którą ci dałem?"
                }
            ]
        },
        {
            "label": "Jedyny w swoim rodzaju",
            "color": "sky",
            "description": "Kiedy coś jest <strong>wyjątkowe</strong> lub <strong>jedyne w swoim rodzaju rodzaj</strong>.",
            "examples": [
                {
                    "en": "słońce, księżyc, Ziemia",
                    "ua": "słońce, księżyc, Ziemia"
                },
                {
                    "en": "the Internet, the radio",
                    "ua": "інтернет, радіо"
                },
                {
                    "en": "the President of Ukraine",
                    "ua": "Президент України"
                }
            ]
        },
        {
            "label": "З визначенням / уточненням",
            "color": "purple",
            "description": "Коли є <strong>уточнення</strong> (of, that, which, тощо).",
            "examples": [
                {
                    "en": "the capital of France",
                    "ua": "столиця Франції"
                },
                {
                    "en": "the man in the red jacket",
                    "ua": "чоловік у червоній куртці"
                },
                {
                    "en": "the book that you recommended",
                    "ua": "книга, яку ти порекомендував"
                }
            ]
        },
        {
            "label": "Geografia i miejsca",
            "color": "amber",
            "description": "Niektóre nazwy geograficzne:",
            "examples": [
                {
                    "en": "USA, Wielka Brytania, Holandia",
                    "ua": "USA, Wielka Brytania, Holandia"
                },
                {
                    "en": "Ocean Spokojny, Dnipro",
                    "ua": "Pacyfik, Dnipro"
                },
                {
                    "en": "Alpy, Karpaty",
                    "ua": "Alpy, Karpaty"
                }
            ],
            "note": "The = „ten sam”, „specyficzny”, „znany”."
        }
    ]
}

{
    "title": "5. Kiedy NIE używać artykułu (Artykuł zerowy)",
    "sections": [
        {
            "label": "Pojęcia ogólne/abstrakcje",
            "color": "amber",
            "description": "Kiedy mówimy o czymś <strong>ogólnie</strong>, pojęcia abstrakcyjne.",
            "examples": [
                {
                    "en": "Kocham muzykę.",
                    "ua": "Kocham muzykę. (muzyka ogólnie)"
                },
                {
                    "en": "Życie jest piękne.",
                    "ua": "Życie jest piękne."
                },
                {
                    "en": "Pieniądze to nie wszystko.",
                    "ua": "Pieniądze to nie wszystko.[[[CODX_30]]]Wielorakość w ogólne"
                }
            ]
        },
        {
            "label": "Множина в загальному",
            "color": "sky",
            "description": "Kiedy mówimy o <strong>wielości w ogóle</strong>.",
            "examples": [
                {
                    "en": "Psy to lojalne zwierzęta.",
                    "ua": "Psy to lojalne zwierzęta. (wszystkie psy)"
                },
                {
                    "en": "Lubię koty.",
                    "ua": "Lubię koty. (koty ogólnie)"
                },
                {
                    "en": "Książki są drogie.",
                    "ua": "Książki są drogie."
                }
            ]
        },
        {
            "label": "Kraje, miasta, nazwy",
            "color": "emerald",
            "description": "Większość <strong>imion własnych</strong> nie wymaga przedimka.",
            "examples": [
                {
                    "en": "Ukraina, Kijów, Londyn",
                    "ua": "Ukraina, Kijów, Londyn"
                },
                {
                    "en": "Mount Everest, jezioro Bajkał",
                    "ua": "Mount Everest, jezioro Bajkał"
                },
                {
                    "en": "John, Maria",
                    "ua": "John, Maria"
                }
            ]
        },
        {
            "label": "Wyrażenia stabilne",
            "color": "purple",
            "description": "W wielu <strong>wyrażeniach regularnych</strong> nie ma przedimka.",
            "examples": [
                {
                    "en": "w domu, w pracy, w szkole",
                    "ua": "w domu, w pracy, w szkole"
                },
                {
                    "en": "autobusem, samochodem, samolotem",
                    "ua": "autobusem, samochodem, samolotem"
                },
                {
                    "en": "idź do łóżka, zjedz śniadanie",
                    "ua": "idź spać, zjedz śniadanie"
                }
            ]
        }
    ]
}

{
    "title": "6. Tabela porównawcza",
    "intro": "Główne przypadki użycia artykułu:",
    "rows": [
        {
            "en": "Pierwsza wzmianka",
            "ua": "Pierwsza wzmianka",
            "note": "A/An: Widziałem psa."
        },
        {
            "en": "Znane / wspomniany",
            "ua": "Znany / wspomniany wspomniany",
            "note": "The: Pies był duży."
        },
        {
            "en": "Wyjątkowe rzeczy",
            "ua": "Wyjątkowe rzeczy",
            "note": "The: słońce, księżyc"
        },
        {
            "en": "Zawody",
            "ua": "Zawody",
            "note": "A/An: Jest nauczycielką."
        },
        {
            "en": "Ogólne / abstrakcyjne",
            "ua": "Ogólne / abstrakcyjne",
            "note": "Ř: Kocham muzykę."
        },
        {
            "en": "Ogólnie liczba mnoga",
            "ua": "Ogólnie liczba mnoga",
            "note": "Ř: Psy są lojalne."
        }
    ],
    "warning": "📌 <strong>A/An</strong> = nowy, jeden z wielu. <strong>The</strong> = konkretny, znany. <strong>Ř</strong> = ogólna koncepcja."
}

{
    "title": "7. Przypadki szczególne",
    "sections": [
        {
            "label": "Przymiotnik + = grupa ludzi",
            "color": "purple",
            "description": "<strong>Przymiotnik +</strong> oznacza grupę ludzi.",
            "examples": [
                {
                    "en": "bogaty, biedny",
                    "ua": "bogaty, biedny (ludzie)"
                },
                {
                    "en": "młodzi, biedni osoby starsze",
                    "ua": "młodzież, osoby starsze"
                },
                {
                    "en": "bezrobotni",
                    "ua": "bezrobotni"
                }
            ]
        },
        {
            "label": "Instrumenty muzyczne",
            "color": "sky",
            "description": "Z instrumentami muzycznymi, których używamy <strong></strong>.",
            "examples": [
                {
                    "en": "graj na pianinie",
                    "ua": "pianino"
                },
                {
                    "en": "graj na gitarze",
                    "ua": "graj na gitarze"
                },
                {
                    "en": "graj na skrzypcach",
                    "ua": "graj na skrzypce"
                }
            ]
        },
        {
            "label": "Pora dnia",
            "color": "amber",
            "description": "Z porą dnia: <strong>rano/popołudniu/wieczór</strong>, ale w nocy</strong>. Typowe błędy osób mówiących po ukraińsku",
            "examples": [
                {
                    "en": "in the morning",
                    "ua": "вранці"
                },
                {
                    "en": "in the afternoon",
                    "ua": "вдень"
                },
                {
                    "en": "at night (без the!)",
                    "ua": "вночі"
                }
            ]
        }
    ]
}

{
    "title": "8. Типові помилки україномовних",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pominięcie artykułu przed zawodem.",
            "wrong": "Ona jest lekarzem.",
            "right": "​​​​ <span class="font-mono">Jest lekarzem lekarz.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "A zamiast An przed dźwiękiem samogłoski.",
            "wrong": "godzina, uczciwa osoba",
            "right": "​​​​​​​​"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Z abstrakcyjnymi pojęciami.",
            "wrong": "Życie jest piękne.",
            "right": "​​​​​​​​​Ukraina."
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Артикль перед країнами (більшість).",
            "wrong": "I live in the Ukraine.",
            "right": " ✅ <span class="font-mono">Mieszkam na Ukrainie.</span>"
        }
    ]
}

{
    "title": "10. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwy artykuł",
    "select_intro": "W puste miejsca wpisz artykuł a, an, the lub Ø (bez przedimka).",
    "selects": [
        {
            "label": "Ona jest ___ inżynierem. (a / an / the / Ø)",
            "prompt": "Który artykuł?"
        },
        {
            "label": "Widziałem dzisiaj ___ słońce. (a / an / the / Ø)",
            "prompt": "Który artykuł?"
        },
        {
            "label": "___ psy są lojalnymi zwierzętami. (a / an / the / Ø)",
            "prompt": "Który artykuł?"
        },
        {
            "label": "Potrzebuję ___ godziny na dokończenie. (a / an / the / Ø)",
            "prompt": "Który artykuł?"
        }
    ],
    "options": [
        "a",
        "an",
        "a",
        "Ř"
    ],
    "input_title": "Ćwiczenie 2. Wybierz lub",
    "input_intro": "Wpisz a lub an przed słowem.",
    "inputs": [
        {
            "before": "___ uniwersytet",
            "after": " →[[CODX_SEG_5]]]___ szczerze odpowiedź"
        },
        {
            "before": "___ honest answer",
            "after": " →"
        },
        {
            "before": "___ Kraj europejski",
            "after": " →"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd za pomocą artykuł.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "On jest nauczycielem.",
            "example_target": "On jest nauczycielem."
        },
        {
            "original": "1. Kocham tę muzykę.",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Mieszka we Francji. / Dowolna — Ilość",
            "placeholder": "Виправ помилку"
        }
    ]
}

{
    "title": "Інші сторінки з категорії Іменники, артиклі та кількість",
    "items": [
        {
            "label": "Articles A / An / The — Артиклі",
            "current": true
        },
        {
            "label": "Countable vs Uncountable — Злічувані / незлічувані",
            "current": false
        },
        {
            "label": "Some / Any — Кількість",
            "current": false
        },
        {
            "label": "Dużo / Wiele / Dużo",
            "current": false
        }
    ]
}
